mapper.select:
select * from sys_artbot_model
and model_name like concat('%', #{modelName}, '%') and model_code like concat('%', #{modelCode}, '%') and status = #{status}
order by is_default desc, model_id desc

mapper.update:
update sys_artbot_model
model_name = #{modelName}, base_url = #{baseUrl}, api_key = #{apiKey}, model_code = #{modelCode}, status = #{status}, is_default = #{isDefault}, temperature = #{temperature}, max_tokens = #{maxTokens}, system_prompt = #{systemPrompt}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where model_id = #{modelId}

mapper.select:
select c.*, m.model_name, m.model_code from sys_artbot_conversation c
inner join sys_artbot_model m on m.model_id = c.model_id
where c.conversation_id = #{conversationId} and c.user_id = #{userId}
